css:
.loader {
  display: inline-block;
  width: 43px;
  height: 43px;
  border-radius: 50%;
  background: var(--loader-color);
  box-shadow: 0 0 0 0 color-mix(in srgb, var(--loader-color) 45%, transparent);
  animation: softPulse 1.1400000000000001s ease-out infinite;
}
@keyframes softPulse { 0% { transform: scale(.82); box-shadow: 0 0 0 0 color-mix(in srgb, var(--loader-color) 45%, transparent); } 70% { transform: scale(1); box-shadow: 0 0 0 22px transparent; } 100% { transform: scale(.82); box-shadow: 0 0 0 0 transparent; } }
